vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;



// sample previous uFrame
ret = texture( sampler_main, vUv ).xyz;

//darken some (note if doing math with numeric values you have to add the decimal point
ret -= q6;//(sin(uTime*100)* 4.0/255.0;

//ret = bee;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;



vec2 imgaspect = vec2( 1.0, 3.0/4.0 );

vec3 tiltuv = 0.0; tiltuv.xy = (vUv) * imgaspect * vec2(1.0,-1.0);

vec3 tiltuv1 = tiltuv;


tiltuv1.xy += vec2( 0.0, 0.71 );

//rotate away from camera, using bottom of matched plane as pivot point
tiltuv1 = rotateX( sang, cang, tiltuv1 );
tiltuv1.x -= xshift;


//depth projection
tiltuv1.xy /= tiltuv1.z + 1.0;
tiltuv1.x -= xshift;



tiltuv1.x += 0.048;
tiltuv1.xy /= imgaspect;
tiltuv1.y *= 1.05;
tiltuv1.x += 1.0;
tiltuv1.x = (tiltuv1.x-0.5)*1.055 + 0.5;

vec2 tiltuv3 = (tiltuv1-vec2(0.0,1.0)) * 1024.0/1436.0 + vec2(0.0,1.0);
tiltuv3.y = 1.2 - tiltuv3.y;
vec2 tiltuv2 = rotateZ( q4, q3, tiltuv1 - 0.5 ) + 0.5;
tiltuv1 = rotateZ( q1, q2, tiltuv1 - 0.5 ) + 0.5;

//sample graphic textures
vec4 circ = textureBias( sampler_beecircs, vec4(tiltuv1.xy,0.0,-0.5)  ); circ.rgb -= 0.5;
circ *= circ.a * audioLow;
vec4 circ2 = textureBias( sampler_beecircs2, vec4(tiltuv2.xy,0.0,-0.5)  ); circ2.rgb -= 0.5;
circ2 *= circ2.a * audioMid * 0.5;
circ += circ2;

vec4 borderblack = length( tiltuv1.xy - 0.5 ) < 0.5;
circ *= borderblack;

vec4 hexes = textureBias( sampler_beehexes, vec4(tiltuv3,0.0,-0.5) ); hexes.rgb -= 0.5;
hexes *= audioHigh * 0.3 + 0.6;
circ = mix( circ, hexes, hexes.a );

//sample bee texture with warped texture coordinates
vec4 bee = texture(sampler_beeonyellownobee, vUv);


circ *= bee.a;


//get recursively warped image from warp shader
vec3 warped = texture(sampler_main, vUv).xyz;



vec2 mainuvs = 1.0- abs( fract( tiltuv3.xy + vec2(-0.15,uTime*0.01) ) * 2.0 - 1.0 );
vec4 main = texture( sampler_main, mainuvs ) * bee.a;


//ret = reftest+0.5;
ret = bee;// + circ;//ref + reftest + circ;
ret += clamp01(main-0.05) * 2.0;

ret += circ;//*audioLow;

vec2 animuv = vUv / vec2( 0.1835*3.0, 0.2441*3.0 ) + vec2(-0.67,-0.38);
vec4 beeanim = texture( sampler_beeanim, animuv + vec2(q7,q8) );
vec4 beecenter = vec4( animuv < 0.33, animuv > 0.0 );
beeanim *= clamp01( dot( beecenter, 1.00 ) - 3.0 );
ret = mix( ret, beeanim, beeanim.a * q5 );


//ret = bee.a;
//ret = circ.a;

  fragColor = ret;
}
